commit be03d00f5f0cc3a997d1a368bee8a1fe93651f48
Author: Mike Kruskal <mkruskal@google.com>
Date:   Fri Jun 30 18:49:33 2023 -0700

    Fix C++20 compatibility bug.

    This was shown to work for C++14, C++17, and C++20 after patched into googletest for the protobuf repo's CI.

    Closes #3659

    PiperOrigin-RevId: 544795507
    Change-Id: I3e0a94f675e78a6ee9aeccae86c23d940efed8eb

diff --git a/googletest/include/gtest/gtest-printers.h b/googletest/include/gtest/gtest-printers.h
index 539d99c4..9a765fd7 100644
--- a/googletest/include/gtest/gtest-printers.h
+++ b/googletest/include/gtest/gtest-printers.h
@@ -473,11 +473,11 @@ GTEST_API_ void PrintTo(wchar_t wc, ::std::ostream* os);

 GTEST_API_ void PrintTo(char32_t c, ::std::ostream* os);
 inline void PrintTo(char16_t c, ::std::ostream* os) {
   PrintTo(ImplicitCast_<char32_t>(c), os);
 }
-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 inline void PrintTo(char8_t c, ::std::ostream* os) {
   PrintTo(ImplicitCast_<char32_t>(c), os);
 }
 #endif

@@ -586,11 +586,11 @@ inline void PrintTo(const unsigned char* s, ::std::ostream* os) {
   PrintTo(ImplicitCast_<const void*>(s), os);
 }
 inline void PrintTo(unsigned char* s, ::std::ostream* os) {
   PrintTo(ImplicitCast_<const void*>(s), os);
 }
-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 // Overloads for u8 strings.
 GTEST_API_ void PrintTo(const char8_t* s, ::std::ostream* os);
 inline void PrintTo(char8_t* s, ::std::ostream* os) {
   PrintTo(ImplicitCast_<const char8_t*>(s), os);
 }
@@ -906,11 +906,11 @@ void UniversalPrintArray(const T* begin, size_t len, ::std::ostream* os) {
 }
 // This overload prints a (const) char array compactly.
 GTEST_API_ void UniversalPrintArray(const char* begin, size_t len,
                                     ::std::ostream* os);

-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 // This overload prints a (const) char8_t array compactly.
 GTEST_API_ void UniversalPrintArray(const char8_t* begin, size_t len,
                                     ::std::ostream* os);
 #endif

diff --git a/googletest/include/gtest/internal/gtest-port.h b/googletest/include/gtest/internal/gtest-port.h
index 52215409..26e4cc3d 100644
--- a/googletest/include/gtest/internal/gtest-port.h
+++ b/googletest/include/gtest/internal/gtest-port.h
@@ -1996,11 +1996,11 @@ inline bool IsUpper(char ch) {
   return isupper(static_cast<unsigned char>(ch)) != 0;
 }
 inline bool IsXDigit(char ch) {
   return isxdigit(static_cast<unsigned char>(ch)) != 0;
 }
-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 inline bool IsXDigit(char8_t ch) {
   return isxdigit(static_cast<unsigned char>(ch)) != 0;
 }
 #endif
 inline bool IsXDigit(char16_t ch) {
diff --git a/googletest/src/gtest-printers.cc b/googletest/src/gtest-printers.cc
index 2b470678..e3acecba 100644
--- a/googletest/src/gtest-printers.cc
+++ b/googletest/src/gtest-printers.cc
@@ -214,11 +214,11 @@ static const char* GetCharWidthPrefix(char) { return ""; }

 static const char* GetCharWidthPrefix(signed char) { return ""; }

 static const char* GetCharWidthPrefix(unsigned char) { return ""; }

-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 static const char* GetCharWidthPrefix(char8_t) { return "u8"; }
 #endif

 static const char* GetCharWidthPrefix(char16_t) { return "u"; }

@@ -230,11 +230,11 @@ static const char* GetCharWidthPrefix(wchar_t) { return "L"; }
 // necessary; returns how c was formatted.
 static CharFormat PrintAsStringLiteralTo(char c, ostream* os) {
   return PrintAsStringLiteralTo(ToChar32(c), os);
 }

-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 static CharFormat PrintAsStringLiteralTo(char8_t c, ostream* os) {
   return PrintAsStringLiteralTo(ToChar32(c), os);
 }
 #endif

@@ -393,11 +393,11 @@ GTEST_ATTRIBUTE_NO_SANITIZE_MEMORY_ GTEST_ATTRIBUTE_NO_SANITIZE_ADDRESS_
 // Prints a (const) char array of 'len' elements, starting at address 'begin'.
 void UniversalPrintArray(const char* begin, size_t len, ostream* os) {
   UniversalPrintCharArray(begin, len, os);
 }

-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 // Prints a (const) char8_t array of 'len' elements, starting at address
 // 'begin'.
 void UniversalPrintArray(const char8_t* begin, size_t len, ostream* os) {
   UniversalPrintCharArray(begin, len, os);
 }
@@ -436,11 +436,11 @@ void PrintCStringTo(const Char* s, ostream* os) {

 }  // anonymous namespace

 void PrintTo(const char* s, ostream* os) { PrintCStringTo(s, os); }

-#ifdef __cpp_char8_t
+#ifdef __cpp_lib_char8_t
 void PrintTo(const char8_t* s, ostream* os) { PrintCStringTo(s, os); }
 #endif

 void PrintTo(const char16_t* s, ostream* os) { PrintCStringTo(s, os); }
